.darma-loader-uiverse-aurora-halo-spinner {
  width: fit-content;
  height: fit-content;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.darma-loader-uiverse-aurora-halo-spinner__container {
  position: relative;
  width: 96px;
  height: 96px;
  border-radius: 50%;
  animation: darma-loader-uiverse-aurora-halo-spinner-rotate_3922 1.2s linear infinite;
  background-color: #9b59b6;
  background-image: linear-gradient(#9b59b6, #84cdfa, #5ad1cd);
}

.darma-loader-uiverse-aurora-halo-spinner__container span {
position: absolute;
border-radius: 50%;
height: 100%;
width: 100%;
background-color: #9b59b6;
background-image: linear-gradient(#9b59b6, #84cdfa, #5ad1cd);
}

.darma-loader-uiverse-aurora-halo-spinner__container span:nth-of-type(1) {
filter: blur(5px);
}

.darma-loader-uiverse-aurora-halo-spinner__container span:nth-of-type(2) {
filter: blur(10px);
}

.darma-loader-uiverse-aurora-halo-spinner__container span:nth-of-type(3) {
filter: blur(25px);
}

.darma-loader-uiverse-aurora-halo-spinner__container span:nth-of-type(4) {
filter: blur(50px);
}

.darma-loader-uiverse-aurora-halo-spinner__container::after {
content: "";
position: absolute;
top: 10px;
left: 10px;
right: 10px;
bottom: 10px;
background-color: #fff;
border: solid 5px #ffffff;
border-radius: 50%;
}

@keyframes darma-loader-uiverse-aurora-halo-spinner-rotate_3922 {
from {
  transform: rotate(0deg);
}

to {
  transform: rotate(360deg);
}
}

